  "code": "def sort_array(arr):
    # Sort by the count of 1s in binary representation (ascending)
    # and then by the integer value (ascending) for ties
    def bit_count_and_value(x):
        # For negative numbers, use absolute value to compute bit count
        # as per example behavior (though problem says non-negative)
        num = abs(x)
        ones = bin(num).count('1')
        return (ones, x)

    return sorted(arr, key=bit_count_and_value)",
